  "FD03": "F03",
  "W942": "W92",
  "S501": "S51",
  "W541": "W51",
  "W542": "W52",
  "R4": "W35"
};

// Get the incoming data
const items = $input.all();

// Process each item
const results = items.map(item => {
  const snValue = item.json.body.sn;

  // Find the key that has this snValue as its value
  const matchedKey = Object.keys(keyValueMap).find(key => keyValueMap[key] === snValue);

  // Return the matched key (or null if not found)
  return {
    original_sn: snValue,
    mapped_key: matchedKey || null
  };
});

// Return the processed results
return results;

